module RefModule (
    input wire clk,
    input wire rst,
    input wire [7:0] current_input,
    output reg [7:0] output_signal
);
    reg [7:0] obf_previous_input;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            obf_previous_input <= 8'b0;
            output_signal <= 8'b0;
        end else begin
            output_signal <= current_input - obf_previous_input;
            obf_previous_input <= current_input;
        end
    end
endmodule
